func (m *MockFolderService) Create(params *repository.CreateFolderParams) (*repository.Folder, error) {
	m.mutex.Lock()
	m.CreateCallCount++
	m.LastCreateParams = params
	m.mutex.Unlock()
	
	if m.ShouldFailCreate {
		return nil, errors.New(m.CreateErrorMessage)
	}
	
	if params == nil {
		return nil, nil
	}
	
	// Basic validation
	if params.Name == "" {
		return nil, errors.New("folder name cannot be empty")
	}
	
	m.mutex.Lock()
	defer m.mutex.Unlock()
	
	// Check for duplicate name within same parent/user
	for _, folder := range m.folders {
		if folder.UserID == params.UserID && 
		   folder.Name == params.Name &&
		   folder.ParentID.Valid == params.ParentID.Valid {
			if !params.ParentID.Valid || folder.ParentID.Bytes == params.ParentID.Bytes {
				return nil, errors.New("folder name already exists in this location")
			}
		}
	}
	
	now := time.Now()
	newFolder := &repository.Folder{
		ID:              uuid.New(),
		ParentID:        params.ParentID,
		UserID:          params.UserID,
		Name:            params.Name,
		Description:     params.Description,
		CreatedDatetime: &now,
		UpdatedDatetime: &now,
	}
	
	// Store folder
	m.folders[newFolder.ID] = newFolder
	
	// Update indexes
	if userFolders, exists := m.foldersByUser[params.UserID]; exists {
		m.foldersByUser[params.UserID] = append(userFolders, newFolder)
	} else {
		m.foldersByUser[params.UserID] = []*repository.Folder{newFolder}
	}
	
	var parentKey uuid.UUID
	if params.ParentID.Valid {
		parentKey = params.ParentID.Bytes
	} else {
		parentKey = uuid.Nil
	}
	
	if parentFolders, exists := m.foldersByParent[parentKey]; exists {
		m.foldersByParent[parentKey] = append(parentFolders, newFolder)
	} else {
		m.foldersByParent[parentKey] = []*repository.Folder{newFolder}
	}
	
	return newFolder, nil
}

