func (m *MockFolderService) Remove(id uuid.UUID) error {
	m.mutex.Lock()
	m.RemoveCallCount++
	m.LastRemoveID = id
	m.mutex.Unlock()
	
	if m.ShouldFailRemove {
		return errors.New(m.RemoveErrorMessage)
	}
	
	m.mutex.Lock()
	defer m.mutex.Unlock()
	
	folder, exists := m.folders[id]
	if !exists {
		return errors.New("folder not found")
	}
	
	// Remove from main storage
	delete(m.folders, id)
	
	// Remove from user index
	if userFolders, exists := m.foldersByUser[folder.UserID]; exists {
		for i, f := range userFolders {
			if f.ID == id {
				m.foldersByUser[folder.UserID] = append(userFolders[:i], userFolders[i+1:]...)
				break
			}
		}
	}
	
	// Remove from parent index
	var parentKey uuid.UUID
	if folder.ParentID.Valid {
		parentKey = folder.ParentID.Bytes
	} else {
		parentKey = uuid.Nil
	}
	
	if parentFolders, exists := m.foldersByParent[parentKey]; exists {
		for i, f := range parentFolders {
			if f.ID == id {
				m.foldersByParent[parentKey] = append(parentFolders[:i], parentFolders[i+1:]...)
				break
			}
		}
	}
	
	return nil
}

func (m *MockFolderService) Move(id uuid.UUID, parentID *uuid.UUID) error {
	m.mutex.Lock()
	m.MoveCallCount++
	m.LastMoveID = id
	m.LastMoveParentID = parentID
	m.mutex.Unlock()
	
	if m.ShouldFailMove {
		return errors.New(m.MoveErrorMessage)
	}
	
	if parentID == nil {
		return nil
	}
	
	m.mutex.Lock()
	defer m.mutex.Unlock()
	
	folder, exists := m.folders[id]
	if !exists {
		return errors.New("folder not found")
	}
	
	// Remove from old parent index
	var oldParentKey uuid.UUID
	if folder.ParentID.Valid {
		oldParentKey = folder.ParentID.Bytes
	} else {
		oldParentKey = uuid.Nil
	}
	
	if parentFolders, exists := m.foldersByParent[oldParentKey]; exists {
		for i, f := range parentFolders {
			if f.ID == id {
				m.foldersByParent[oldParentKey] = append(parentFolders[:i], parentFolders[i+1:]...)
				break
			}
		}
	}
	
	// Update folder's parent
	if *parentID == uuid.Nil {
		folder.ParentID = pgtype.UUID{Valid: false}
	} else {
		folder.ParentID = pgtype.UUID{Bytes: *parentID, Valid: true}
	}
	
	// Add to new parent index
	var newParentKey uuid.UUID
	if folder.ParentID.Valid {
		newParentKey = folder.ParentID.Bytes
	} else {
		newParentKey = uuid.Nil
	}
	
	if parentFolders, exists := m.foldersByParent[newParentKey]; exists {
		m.foldersByParent[newParentKey] = append(parentFolders, folder)
	} else {
		m.foldersByParent[newParentKey] = []*repository.Folder{folder}
	}
	
	return nil
}

